create database PowerBI_SQL_Data;
use PowerBI_SQL_Data;

CREATE TABLE DepartmentData (
    DepartmentID INT PRIMARY KEY,
    DepartmentName VARCHAR(50)
);

CREATE TABLE CustomerData (
    CustomerID INT PRIMARY KEY,
    Name VARCHAR(100),
    Region VARCHAR(50),
    Segment VARCHAR(50),
    Email VARCHAR(100)
);

CREATE TABLE ProductData (
    ProductID INT PRIMARY KEY,
    ProductName VARCHAR(100),
    Category VARCHAR(50),
    Price DECIMAL(10 , 2 ),
    Supplier VARCHAR(100)
);

CREATE TABLE EmployeeData (
    EmployeeID INT PRIMARY KEY,
    Name VARCHAR(100),
    DepartmentID INT,
    HireDate DATE,
    Email VARCHAR(100),
    FOREIGN KEY (DepartmentID)
        REFERENCES DepartmentData (DepartmentID)
);

CREATE TABLE SalesData (
    SaleID INT PRIMARY KEY,
    SaleDate DATE,
    CustomerID INT,
    ProductID INT,
    EmployeeID INT,
    Quantity INT,
    UnitPrice DECIMAL(10 , 2 ),
    TotalSale DECIMAL(10 , 2 ),
    FOREIGN KEY (CustomerID)
        REFERENCES CustomerData (CustomerID),
    FOREIGN KEY (ProductID)
        REFERENCES ProductData (ProductID),
    FOREIGN KEY (EmployeeID)
        REFERENCES EmployeeData (EmployeeID)
);

CREATE TABLE FinancialData (
    ExpenseID INT PRIMARY KEY,
    ExpenseDate DATE,
    Category VARCHAR(50),
    Amount DECIMAL(10 , 2 ),
    DepartmentID INT,
    FOREIGN KEY (DepartmentID)
        REFERENCES DepartmentData (DepartmentID)
);

select * from financialdata;










